"""Uvicorn main server loop and configuration."""
from __future__ import annotations

import asyncio
import logging
import os
import signal
import socket
import sys
from typing import Any, Callable, Dict, List, Optional, Tuple, Type, Union

logger = logging.getLogger("uvicorn")


class Config:
    """Server configuration container."""

    def __init__(
        self,
        app: Union[str, Callable],
        *,
        host: str = "127.0.0.1",
        port: int = 8000,
        debug: bool = False,
        workers: Optional[int] = None,
        env_file: Optional[str] = None,
        log_level: str = "info",
        log_config: Optional[Dict] = None,
        access_log: bool = True,
        use_colors: Optional[bool] = None,
        reload: bool = False,
        reload_dirs: Optional[List[str]] = None,
        reload_delay: float = 0.25,
        loop: str = "auto",
        http: str = "auto",
        ws: str = "auto",
        lifespan: str = "auto",
        interface: str = "auto",
        root_path: str = "",
        proxy_headers: bool = True,
        server_header: bool = True,
        date_header: bool = True,
        limit_concurrency: Optional[int] = None,
        limit_max_requests: Optional[int] = None,
        backlog: int = 2048,
        timeout_keep_alive: int = 5,
        timeout_notify: int = 30,
        ssl_keyfile: Optional[str] = None,
        ssl_certfile: Optional[str] = None,
        ssl_ca_certs: Optional[str] = None,
        ssl_ciphers: str = "TLSv1",
        headers: Optional[List[Tuple[str, str]]] = None,
        factory: bool = False,
    ) -> None:
        self.app = app
        self.host = host
        self.port = port
        self.debug = debug
        self.workers = workers
        self.log_level = log_level.upper()
        self.access_log = access_log
        self.reload = reload
        self.reload_dirs = reload_dirs or []
        self.reload_delay = reload_delay
        self.loop = loop
        self.http = http
        self.ws = ws
        self.lifespan = lifespan
        self.root_path = root_path
        self.proxy_headers = proxy_headers
        self.server_header = server_header
        self.date_header = date_header
        self.limit_concurrency = limit_concurrency
        self.limit_max_requests = limit_max_requests
        self.backlog = backlog
        self.timeout_keep_alive = timeout_keep_alive
        self.ssl_keyfile = ssl_keyfile
        self.ssl_certfile = ssl_certfile
        self.headers = headers or []
        self.factory = factory
        self.loaded = False
        self.loaded_app: Optional[Callable] = None

    def load(self) -> None:
        if self.loaded:
            return
        if isinstance(self.app, str):
            module_path, app_name = self.app.rsplit(":", 1)
            import importlib
            module = importlib.import_module(module_path)
            self.loaded_app = getattr(module, app_name)
        else:
            self.loaded_app = self.app
        self.loaded = True

    @property
    def bind(self) -> str:
        return f"{self.host}:{self.port}"


class ServerState:
    """Shared state between server workers."""

    def __init__(self) -> None:
        self.total_requests = 0
        self.connections: set = set()
        self.tasks: set = set()
        self.default_headers: List[Tuple[bytes, bytes]] = []


class Server:
    """
    ASGI server that manages the event loop and handles connections.

    Usage::

        config = Config(app="myapp:app", host="0.0.0.0", port=8000)
        server = Server(config=config)
        server.run()
    """

    def __init__(self, config: Config) -> None:
        self.config = config
        self.server_state = ServerState()
        self.started = False
        self.should_exit = False
        self.force_exit = False
        self.lifespan = None

    def run(self, sockets: Optional[List[socket.socket]] = None) -> None:
        self.config.load()
        try:
            asyncio.run(self.serve(sockets=sockets))
        except KeyboardInterrupt:
            pass

    async def serve(self, sockets: Optional[List[socket.socket]] = None) -> None:
        config = self.config
        logger.info(f"Started server process [{os.getpid()}]")
        logger.info(f"Waiting for application startup.")
        logger.info(f"Application startup complete.")
        logger.info(f"Uvicorn running on http://{config.host}:{config.port} (Press CTRL+C to quit)")

        try:
            await self.main_loop()
        except Exception as exc:
            logger.error(f"Server error: {exc}")
            raise

        logger.info("Shutting down")
        logger.info("Finished server process")

    async def main_loop(self) -> None:
        while not self.should_exit:
            await asyncio.sleep(0.1)

    def install_signal_handlers(self) -> None:
        loop = asyncio.get_event_loop()
        for sig in (signal.SIGINT, signal.SIGTERM):
            loop.add_signal_handler(sig, self.handle_exit, sig, None)

    def handle_exit(self, sig: int, frame: Any) -> None:
        self.should_exit = True
